choose.when:
select locale,status_label,eyebrow,title,summary,seo_title,seo_description
from portfolio.project_translation where project_id=#{projectId}
order by locale

select media_asset_id,usage,sort_order,layout,object_position,credit,source_url
from portfolio.project_media where project_id=#{projectId}
order by sort_order,usage,media_asset_id

select id,block_type,sort_order,visible,width,alignment,emphasis,columns,version
from portfolio.project_content_block where project_id=#{projectId}
order by sort_order,id

mapper.update:
update portfolio.project
set slug=#{workspace.slug},number_label=#{workspace.numberLabel},sort_order=#{workspace.sortOrder},
    featured=#{workspace.featured},visible=#{workspace.visible},publication_dirty=true,
    version=version+1,updated_at=#{updatedAt}
where id=#{workspace.id} and version=#{expectedVersion}

update portfolio.project
set publication_dirty=true,version=version+1,updated_at=#{updatedAt}
where id in
#{id}

update portfolio.project
set publication_dirty=false,version=version+1,updated_at=#{updatedAt}
where id=#{projectId} and version=#{expectedVersion}

update portfolio.project p
set sort_order=v.sort_order,publication_dirty=true,version=p.version+1,updated_at=#{updatedAt}
from (values
  (#{r.id}::uuid,#{r.sortOrder}::integer)
) as v(id,sort_order)
where p.id=v.id
